import React, { useState } from "react";
import API from "../api/api";

function UploaderDashboard() {
  const [data, setData] = useState({ bus_no: "", route_id: "", stop_id: "", boarding_count: "", alighting_count: "", timestamp: "" });
  const [message, setMessage] = useState("");

  const handleSubmit = () => {
    API.post("/uploader/observations/upload", data)
      .then((res) => setMessage(res.data.message))
      .catch((err) => console.log(err));
  };

  return (
    <div>
      <h2 className="text-xl font-bold mb-2">Upload Observation</h2>
      <input placeholder="Bus No" onChange={(e) => setData({ ...data, bus_no: e.target.value })} className="border p-1 m-1"/>
      <input placeholder="Route ID" onChange={(e) => setData({ ...data, route_id: e.target.value })} className="border p-1 m-1"/>
      <input placeholder="Stop ID" onChange={(e) => setData({ ...data, stop_id: e.target.value })} className="border p-1 m-1"/>
      <input placeholder="Boarding Count" onChange={(e) => setData({ ...data, boarding_count: e.target.value })} className="border p-1 m-1"/>
      <input placeholder="Alighting Count" onChange={(e) => setData({ ...data, alighting_count: e.target.value })} className="border p-1 m-1"/>
      <input placeholder="Timestamp" onChange={(e) => setData({ ...data, timestamp: e.target.value })} className="border p-1 m-1"/>
      <button onClick={handleSubmit} className="bg-purple-500 text-white px-4 py-2 rounded m-1">Submit</button>
      <div className="mt-2">{message}</div>
    </div>
  );
}

export default UploaderDashboard;
